/**
 * Resolve the granted spell UUID for a specific rank, accounting for sub-choices.
 *
 * For choice-dependent subclasses (e.g., Elemental bloodline), the arrays in
 * grantedSpells align with the choiceOptions array by index. If the user picked
 * "air" and choiceOptions[0].slug === "air", then grantedSpells.cantrip[0] is
 * the air cantrip.
 *
 * @param {string} rankKey - "cantrip", "1", "2", ... "9"
 * @param {Object} data - the SUBCLASS_SPELLS entry
 * @param {Object} choices - user's choices, e.g. { elementalBloodline: "air" }
 * @returns {string|null} spell UUID or null
 */
function resolveRankSpell(rankKey, data, choices) {
  // 1. Check explicit choices map first (manually verified, always correct)
  if (data.choices && data.choiceFlag) {
    const choiceValue = choices[data.choiceFlag];
    if (choiceValue && data.choices[choiceValue]?.[rankKey]) {
      return data.choices[choiceValue][rankKey];
    }
  }

  // 2. Check shared grantedSpells
  const spells = data.grantedSpells?.[rankKey];
  if (!spells) return null;
  if (typeof spells === 'string') return spells;
  if (!Array.isArray(spells)) return null;
  if (spells.length === 1) return spells[0];

  // 3. Array without explicit choices map — fall back to index matching
  if (data.choiceFlag && data.choiceOptions) {
    const choiceValue = choices[data.choiceFlag];
    if (choiceValue) {
      const idx = data.choiceOptions.findIndex((o) =>
        (typeof o === 'string' ? o : o.slug) === choiceValue,
      );
      if (idx >= 0 && idx < spells.length) return spells[idx];
    }
  }

  return null;
}

/**
 * Resolve granted spells for a subclass.
 *
 * @param {string} subclassSlug
 * @param {Object} choices - e.g. { elementalBloodline: "air" }
 * @param {number|string|null} rank - specific rank, or null for creation (cantrip + rank 1 + focus)
 * @returns {Object|null}
 */
export function resolveSubclassSpells(subclassSlug, choices = {}, rank = null) {
  let data = SUBCLASS_SPELLS[subclassSlug];
  // Fallback: try normalizing the slug (strip colons, extra dashes)
  if (!data && subclassSlug) {
    const normalized = subclassSlug.replace(/[:\s]+/g, '-').replace(/^-+|-+$/g, '').replace(/-{2,}/g, '-');
    data = SUBCLASS_SPELLS[normalized];
  }
  if (!data) return null;

  if (rank === null) {
    return {
      cantrip: resolveRankSpell('cantrip', data, choices),
      rank1: resolveRankSpell('1', data, choices),
      focusSpell: data.focusSpells?.initial ?? null,
    };
  }

  const key = rank === 0 || rank === 'cantrip' ? 'cantrip' : String(rank);
  return {
    grantedSpell: resolveRankSpell(key, data, choices),
    focusSpells: data.focusSpells ?? {},
  };
}

/**
 * Resolve all level-1 conscious-mind spell grants for psychic creation.
 * This includes the 1st-rank granted spell and the three level-1 psi cantrips
 * (two standard psi cantrips plus the surface unique psi cantrip).
 *
 * @param {string} subclassSlug
 * @returns {{cantrips: string[], rank1s: string[]}}
 */
export function resolvePsychicLevelOneSpells(subclassSlug) {
  let data = SUBCLASS_SPELLS[subclassSlug];
  if (!data && subclassSlug) {
    const normalized = subclassSlug.replace(/[:\s]+/g, '-').replace(/^-+|-+$/g, '').replace(/-{2,}/g, '-');
    data = SUBCLASS_SPELLS[normalized];
  }
  if (!data) return { cantrips: [], rank1s: [] };

  const cantripData = data.grantedSpells?.cantrip;
  const cantrips = Array.isArray(cantripData)
    ? cantripData.slice(0, 3)
    : typeof cantripData === 'string'
      ? [cantripData]
      : [];

  const rank1 = resolveRankSpell('1', data, {});

  return {
    cantrips,
    rank1s: rank1 ? [rank1] : [],
  };
}
